#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
class Solution {
public:
    bool solve(vector<int>& nums) {
        int n = nums.size();
        vector<int> result;
        function<void(vector<int>&, int)> merge_sort;
        merge_sort = [&](vector<int>& nums, int mid) {
            if (mid <= 0) {
                return;
            }
            vector<int> left(nums.begin(), nums.begin() + mid);
            vector<int> right(nums.begin() + mid, nums.end());
            merge_sort(left, mid / 2);
            merge_sort(right, (mid + 1) / 2);
            int i = 0, j = 0;
            while (i < left.size() && j < right.size()) {
                if (left[i] <= right[j]) {
                    result.push_back(left[i]);
                    i++;
                } else {
                    result.push_back(right[j]);
                    j++;
                }
            }
            while (i < left.size()) {
                result.push_back(left[i]);
                i++;
            }
            while (j < right.size()) {
                result.push_back(right[j]);
                j++;
            }
            nums = result;
        };
        merge_sort(nums, n);
        return nums == vector<int>(nums.begin(), nums.end());
    }
};

int main() {
    Solution solution;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int& x : nums) {
        cin >> x;
    }
    bool result = solution.solve(nums);
    cout << (result ? 'YES' : 'NO') << endl;
    return 0;
}
